<template><main class='page'><header class='page-header'><h1 class='page-title'>菜品分类</h1><p class='page-subtitle'>按菜系、菜品类型快速筛选。</p></header><section class='filters'><button v-for='item in cuisineList' :key='item' :class='{active:currentCuisine===item}' @click='currentCuisine=item'>{{item}}</button></section><section class='type-scroll'><button v-for='item in categories' :key='item' :class='{active:currentCategory===item}' @click='currentCategory=item'>{{item}}</button></section><DishCard v-for='dish in filteredDishes' :key='dish.id' :dish='dish'/></main></template><script setup>import{computed,onMounted,ref,watchEffect}from'vue';import{useRoute}from'vue-router';import DishCard from'../components/DishCard.vue';import{useRecipes}from'../composables/useRecipes';const route=useRoute();const{dishes,cuisines,loadRecipes}=useRecipes();const currentCuisine=ref(route.query.cuisine||'粤菜'),currentCategory=ref('全部');onMounted(loadRecipes);watchEffect(()=>{if(route.query.cuisine){currentCuisine.value=route.query.cuisine;currentCategory.value='全部'}});const cuisineList=computed(()=>cuisines.value.map(x=>x.name));const categories=computed(()=>['全部',...new Set(dishes.value.filter(x=>x.cuisine===currentCuisine.value).map(x=>x.category))]);const filteredDishes=computed(()=>dishes.value.filter(x=>x.cuisine===currentCuisine.value&&(currentCategory.value==='全部'||x.category===currentCategory.value)))</script><style scoped>.filters{display:grid;grid-template-columns:repeat(4,1fr);gap:9px;margin-bottom:14px}.filters button,.type-scroll button{border:0;border-radius:18px;height:48px;background:#fff;color:var(--sub);font-weight:900;box-shadow:0 8px 25px rgba(0,0,0,.04)}.filters button.active,.type-scroll button.active{background:var(--blue);color:#fff}.type-scroll{display:flex;gap:10px;overflow-x:auto;padding:4px 2px 16px;margin-bottom:4px}.type-scroll button{flex:0 0 auto;padding:0 18px}</style>
